(window.webpackJsonp=window.webpackJsonp||[]).push([[887],{866:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number}</span> <span class=\\"hljs-variable\\">n</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[][]}</span> <span class=\\"hljs-variable\\">preferences</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[][]}</span> <span class=\\"hljs-variable\\">pairs</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> unhappyFriends = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">n, preferences, pairs</span>) </span>{\\n    <span class=\\"hljs-keyword\\">let</span> perHash=[]\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;preferences.length;i++){\\n        <span class=\\"hljs-keyword\\">if</span>(perHash[i]==<span class=\\"hljs-literal\\">null</span>)perHash[i]={}\\n        <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> j=<span class=\\"hljs-number\\">0</span>;j&lt;preferences[i].length;j++){\\n            <span class=\\"hljs-keyword\\">let</span> u=preferences[i][j]\\n            perHash[i][u]=preferences[i].length-j\\n        }\\n    }\\n    <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">check</span>(<span class=\\"hljs-params\\">x,y,u,v</span>)</span>{\\n        <span class=\\"hljs-keyword\\">if</span>(perHash[x][u]&gt;perHash[x][y] &amp;&amp; perHash[u][x]&gt;perHash[u][v])<span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-literal\\">true</span>\\n        <span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-literal\\">false</span>\\n    }\\n    <span class=\\"hljs-comment\\">// console.log(perHash)</span>\\n    <span class=\\"hljs-keyword\\">let</span> unHappy=<span class=\\"hljs-built_in\\">Array</span>(n).fill(<span class=\\"hljs-literal\\">false</span>)\\n    <span class=\\"hljs-keyword\\">let</span> res=<span class=\\"hljs-number\\">0</span>\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;pairs.length;i++){\\n        <span class=\\"hljs-keyword\\">let</span> [x,y]=pairs[i]\\n        <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> j=<span class=\\"hljs-number\\">0</span>;j&lt;pairs.length;j++){\\n            <span class=\\"hljs-keyword\\">if</span>(i===j)<span class=\\"hljs-keyword\\">continue</span>\\n            <span class=\\"hljs-keyword\\">let</span> [u,v]=pairs[j]\\n            <span class=\\"hljs-comment\\">// let xHappy=true</span>\\n            <span class=\\"hljs-comment\\">// let yHappy=true</span>\\n            <span class=\\"hljs-comment\\">// console.log(x,y,u,v)</span>\\n            <span class=\\"hljs-keyword\\">if</span>(check(x,y,u,v) || check(x,y,v,u)){\\n                <span class=\\"hljs-keyword\\">if</span>(!unHappy[x]){\\n                    unHappy[x]=<span class=\\"hljs-literal\\">true</span>\\n                    res++\\n                }\\n            }\\n            <span class=\\"hljs-keyword\\">if</span>(check(y,x,u,v) || check(y,x,v,u)){\\n                <span class=\\"hljs-keyword\\">if</span>(!unHappy[y]){\\n                    unHappy[y]=<span class=\\"hljs-literal\\">true</span>\\n                    res++\\n                }\\n            }\\n            <span class=\\"hljs-comment\\">// console.log(xHappy,yHappy,\'---\')</span>\\n            <span class=\\"hljs-comment\\">// if(!xHappy &amp;&amp; !yHappy)break</span>\\n        }\\n    }\\n    <span class=\\"hljs-keyword\\">return</span> res\\n};\\n</code></pre>\\n"],"titleSlug":"count-unhappy-friends","hasThinking":false,"content":"<p>\u7ed9\u4f60\u4e00\u4efd <code>n</code> \u4f4d\u670b\u53cb\u7684\u4eb2\u8fd1\u7a0b\u5ea6\u5217\u8868\uff0c\u5176\u4e2d <code>n</code> \u603b\u662f <strong>\u5076\u6570</strong> \u3002</p>\\n\\n<p>\u5bf9\u6bcf\u4f4d\u670b\u53cb <code>i</code>\uff0c<code>preferences[i]</code> \u5305\u542b\u4e00\u4efd <strong>\u6309\u4eb2\u8fd1\u7a0b\u5ea6\u4ece\u9ad8</strong><strong>\u5230\u4f4e\u6392\u5217</strong> \u7684\u670b\u53cb\u5217\u8868\u3002\u6362\u53e5\u8bdd\u8bf4\uff0c\u6392\u5728\u5217\u8868\u524d\u9762\u7684\u670b\u53cb\u4e0e <code>i</code> \u7684\u4eb2\u8fd1\u7a0b\u5ea6\u6bd4\u6392\u5728\u5217\u8868\u540e\u9762\u7684\u670b\u53cb\u66f4\u9ad8\u3002\u6bcf\u4e2a\u5217\u8868\u4e2d\u7684\u670b\u53cb\u5747\u4ee5 <code>0</code> \u5230 <code>n-1</code> \u4e4b\u95f4\u7684\u6574\u6570\u8868\u793a\u3002</p>\\n\\n<p>\u6240\u6709\u7684\u670b\u53cb\u88ab\u5206\u6210\u51e0\u5bf9\uff0c\u914d\u5bf9\u60c5\u51b5\u4ee5\u5217\u8868 <code>pairs</code> \u7ed9\u51fa\uff0c\u5176\u4e2d <code>pairs[i] = [x<sub>i</sub>, y<sub>i</sub>]</code> \u8868\u793a <code>x<sub>i</sub></code> \u4e0e <code>y<sub>i</sub></code> \u914d\u5bf9\uff0c\u4e14 <code>y<sub>i</sub></code> \u4e0e <code>x<sub>i</sub></code> \u914d\u5bf9\u3002</p>\\n\\n<p>\u4f46\u662f\uff0c\u8fd9\u6837\u7684\u914d\u5bf9\u60c5\u51b5\u53ef\u80fd\u4f1a\u662f\u5176\u4e2d\u90e8\u5206\u670b\u53cb\u611f\u5230\u4e0d\u5f00\u5fc3\u3002\u5728 <code>x</code> \u4e0e <code>y</code> \u914d\u5bf9\u4e14 <code>u</code> \u4e0e <code>v</code> \u914d\u5bf9\u7684\u60c5\u51b5\u4e0b\uff0c\u5982\u679c\u540c\u65f6\u6ee1\u8db3\u4e0b\u8ff0\u4e24\u4e2a\u6761\u4ef6\uff0c<code>x</code> \u5c31\u4f1a\u4e0d\u5f00\u5fc3\uff1a</p>\\n\\n<ul>\\n\\t<li><code>x</code> \u4e0e <code>u</code> \u7684\u4eb2\u8fd1\u7a0b\u5ea6\u80dc\u8fc7 <code>x</code> \u4e0e <code>y</code>\uff0c\u4e14</li>\\n\\t<li><code>u</code> \u4e0e <code>x</code> \u7684\u4eb2\u8fd1\u7a0b\u5ea6\u80dc\u8fc7 <code>u</code> \u4e0e <code>v</code></li>\\n</ul>\\n\\n<p>\u8fd4\u56de <strong>\u4e0d\u5f00\u5fc3\u7684\u670b\u53cb\u7684\u6570\u76ee</strong> \u3002</p>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>n = 4, preferences = [[1, 2, 3], [3, 2, 0], [3, 1, 0], [1, 2, 0]], pairs = [[0, 1], [2, 3]]\\n<strong>\u8f93\u51fa\uff1a</strong>2\\n<strong>\u89e3\u91ca\uff1a</strong>\\n\u670b\u53cb 1 \u4e0d\u5f00\u5fc3\uff0c\u56e0\u4e3a\uff1a\\n- <strong>1 \u4e0e 0 </strong>\u914d\u5bf9\uff0c\u4f46 <strong>1 \u4e0e 3</strong> \u7684\u4eb2\u8fd1\u7a0b\u5ea6\u6bd4 <strong>1 \u4e0e 0</strong> \u9ad8\uff0c\u4e14\\n- <strong>3 \u4e0e 1</strong> \u7684\u4eb2\u8fd1\u7a0b\u5ea6\u6bd4 <strong>3 \u4e0e 2</strong> \u9ad8\u3002\\n\u670b\u53cb 3 \u4e0d\u5f00\u5fc3\uff0c\u56e0\u4e3a\uff1a\\n- 3 \u4e0e 2 \u914d\u5bf9\uff0c\u4f46 <strong>3 \u4e0e 1</strong> \u7684\u4eb2\u8fd1\u7a0b\u5ea6\u6bd4 <strong>3 \u4e0e 2</strong> \u9ad8\uff0c\u4e14\\n- <strong>1 \u4e0e 3</strong> \u7684\u4eb2\u8fd1\u7a0b\u5ea6\u6bd4 <strong>1 \u4e0e 0</strong> \u9ad8\u3002\\n\u670b\u53cb 0 \u548c 2 \u90fd\u662f\u5f00\u5fc3\u7684\u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>n = 2, preferences = [[1], [0]], pairs = [[1, 0]]\\n<strong>\u8f93\u51fa\uff1a</strong>0\\n<strong>\u89e3\u91ca\uff1a</strong>\u670b\u53cb 0 \u548c 1 \u90fd\u5f00\u5fc3\u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>n = 4, preferences = [[1, 3, 2], [2, 3, 0], [1, 3, 0], [0, 2, 1]], pairs = [[1, 3], [0, 2]]\\n<strong>\u8f93\u51fa\uff1a</strong>4\\n</pre>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>2 &lt;= n &lt;= 500</code></li>\\n\\t<li><code>n</code> \u662f\u5076\u6570</li>\\n\\t<li><code>preferences.length&nbsp;== n</code></li>\\n\\t<li><code>preferences[i].length&nbsp;== n - 1</code></li>\\n\\t<li><code>0 &lt;= preferences[i][j] &lt;= n - 1</code></li>\\n\\t<li><code>preferences[i]</code> \u4e0d\u5305\u542b <code>i</code></li>\\n\\t<li><code>preferences[i]</code> \u4e2d\u7684\u6240\u6709\u503c\u90fd\u662f\u72ec\u4e00\u65e0\u4e8c\u7684</li>\\n\\t<li><code>pairs.length&nbsp;== n/2</code></li>\\n\\t<li><code>pairs[i].length&nbsp;== 2</code></li>\\n\\t<li><code>x<sub>i</sub> != y<sub>i</sub></code></li>\\n\\t<li><code>0 &lt;= x<sub>i</sub>, y<sub>i</sub>&nbsp;&lt;= n - 1</code></li>\\n\\t<li>\u6bcf\u4f4d\u670b\u53cb\u90fd <strong>\u6070\u597d</strong> \u88ab\u5305\u542b\u5728\u4e00\u5bf9\u4e2d</li>\\n</ul>\\n","title":"1583. \u7edf\u8ba1\u4e0d\u5f00\u5fc3\u7684\u670b\u53cb","relatedTags":["\u6570\u7ec4"],"difficult":"Middle","lang":["javascript"],"uniqueID":"1583"}')}}]);